-- 0001_init.sql
-- Initial schema for go-runtime.
-- Convention: all timestamps are unix milliseconds (INTEGER).
-- IDs are ULID-style strings (26 chars) generated by Go runtime.

PRAGMA journal_mode = WAL;
PRAGMA synchronous = NORMAL;
PRAGMA foreign_keys = ON;
PRAGMA busy_timeout = 5000;

-- sessions
CREATE TABLE IF NOT EXISTS sessions (
    id              TEXT PRIMARY KEY,
    cwd             TEXT NOT NULL,
    model           TEXT,
    title           TEXT,
    created_at      INTEGER NOT NULL,
    updated_at      INTEGER NOT NULL,
    -- pointer to the currently-effective compaction version (NULL = none yet)
    active_compaction_id TEXT
);
CREATE INDEX IF NOT EXISTS idx_sessions_updated ON sessions(updated_at DESC);

-- tasks
CREATE TABLE IF NOT EXISTS tasks (
    id              TEXT PRIMARY KEY,
    session_id      TEXT,
    parent_task_id  TEXT,
    prompt          TEXT NOT NULL,
    model           TEXT,
    cwd             TEXT NOT NULL,
    -- state machine: see .opencode/design/state-machine.md
    status          TEXT NOT NULL CHECK (status IN (
        'pending','queued','running','blocked','retrying',
        'completed','failed','timeout','cancelled','manual_attention'
    )),
    priority        INTEGER NOT NULL DEFAULT 0,
    max_attempts    INTEGER NOT NULL DEFAULT 1,
    attempts_used   INTEGER NOT NULL DEFAULT 0,
    deadline_ms     INTEGER,
    created_at      INTEGER NOT NULL,
    updated_at      INTEGER NOT NULL,
    started_at      INTEGER,
    finished_at     INTEGER,
    last_error      TEXT,
    FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE SET NULL
);
CREATE INDEX IF NOT EXISTS idx_tasks_session ON tasks(session_id);
CREATE INDEX IF NOT EXISTS idx_tasks_status_updated ON tasks(status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_tasks_parent ON tasks(parent_task_id);

-- task_attempts (one row per try)
CREATE TABLE IF NOT EXISTS task_attempts (
    id              TEXT PRIMARY KEY,
    task_id         TEXT NOT NULL,
    attempt_no      INTEGER NOT NULL,
    pid             INTEGER,
    started_at      INTEGER NOT NULL,
    finished_at     INTEGER,
    exit_code       INTEGER,
    error           TEXT,
    -- lease for heartbeat-based stuck detection
    lease_until_ms  INTEGER,
    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,
    UNIQUE (task_id, attempt_no)
);
CREATE INDEX IF NOT EXISTS idx_attempts_task ON task_attempts(task_id);
CREATE INDEX IF NOT EXISTS idx_attempts_lease ON task_attempts(lease_until_ms)
    WHERE lease_until_ms IS NOT NULL;

-- task_events (append-only event log; seq is global monotonic)
CREATE TABLE IF NOT EXISTS task_events (
    seq             INTEGER PRIMARY KEY AUTOINCREMENT,
    ts              INTEGER NOT NULL,
    type            TEXT NOT NULL,
    scope           TEXT NOT NULL CHECK (scope IN ('task','session','runtime')),
    task_id         TEXT,
    session_id      TEXT,
    attempt_id      TEXT,
    -- JSON payload; large fields should be offloaded to artifacts
    payload         TEXT NOT NULL DEFAULT '{}'
);
CREATE INDEX IF NOT EXISTS idx_events_task_seq    ON task_events(task_id, seq);
CREATE INDEX IF NOT EXISTS idx_events_session_seq ON task_events(session_id, seq);
CREATE INDEX IF NOT EXISTS idx_events_type        ON task_events(type);

-- checkpoints (one row per snapshot during running)
CREATE TABLE IF NOT EXISTS checkpoints (
    id                  TEXT PRIMARY KEY,
    task_id             TEXT NOT NULL,
    attempt_id          TEXT NOT NULL,
    created_at          INTEGER NOT NULL,
    transcript_cursor   INTEGER NOT NULL DEFAULT 0,
    runtime_cursor      INTEGER NOT NULL DEFAULT 0,
    state_blob          TEXT,
    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,
    FOREIGN KEY (attempt_id) REFERENCES task_attempts(id) ON DELETE CASCADE
);
CREATE INDEX IF NOT EXISTS idx_checkpoints_task ON checkpoints(task_id, created_at DESC);

-- compactions (two-phase commit: proposed -> committed | rolled_back)
CREATE TABLE IF NOT EXISTS compactions (
    id              TEXT PRIMARY KEY,
    session_id      TEXT NOT NULL,
    version         INTEGER NOT NULL,
    status          TEXT NOT NULL CHECK (status IN ('proposed','committed','rolled_back')),
    from_seq        INTEGER NOT NULL,
    to_seq          INTEGER NOT NULL,
    proposed_at     INTEGER NOT NULL,
    committed_at    INTEGER,
    rolled_back_at  INTEGER,
    -- pointer to artifact holding compacted transcript
    artifact_id     TEXT,
    reason          TEXT,
    FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE CASCADE,
    UNIQUE (session_id, version)
);
CREATE INDEX IF NOT EXISTS idx_compactions_session ON compactions(session_id, version DESC);

-- artifacts (large blobs live on disk; this table tracks references)
CREATE TABLE IF NOT EXISTS artifacts (
    id              TEXT PRIMARY KEY,
    kind            TEXT NOT NULL,        -- 'stdout' | 'stderr' | 'tool_output' | 'compaction' | 'misc'
    task_id         TEXT,
    session_id      TEXT,
    path            TEXT NOT NULL,        -- absolute path on disk
    bytes           INTEGER NOT NULL DEFAULT 0,
    sha256          TEXT,
    created_at      INTEGER NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_artifacts_task    ON artifacts(task_id);
CREATE INDEX IF NOT EXISTS idx_artifacts_session ON artifacts(session_id);

-- schema_migrations (track applied migrations)
CREATE TABLE IF NOT EXISTS schema_migrations (
    version     INTEGER PRIMARY KEY,
    name        TEXT NOT NULL,
    applied_at  INTEGER NOT NULL
);
